process.env.STORAGE_DIR = "test-storage";
const path = require("path");
const fs = require("fs");
const { downloadURIToFile } = require("../../../utils/downloadURIToFile");
const { WATCH_DIRECTORY } = require("../../../utils/constants");

// Mock fetch globally
const originalFetch = global.fetch;

describe("downloadURIToFile", () => {
  beforeEach(() => {
    // Ensure hotdir exists
    if (!fs.existsSync(WATCH_DIRECTORY))
      fs.mkdirSync(WATCH_DIRECTORY, { recursive: true });
  });

  afterEach(() => {
    global.fetch = originalFetch;
  });

  it("should append file extension based on Content-Type header when URL has no explicit extension", async () => {
    // Simulate a response with application/pdf content type
    const mockBody = {
      pipe: jest.fn(),
      [Symbol.asyncIterator]: async function* () {
        yield Buffer.from("fake pdf content");
      },
    };

    global.fetch = jest.fn().mockResolvedValue({
      ok: true,
      status: 200,
      statusText: "OK",
      headers: {
        get: jest.fn().mockReturnValue("application/pdf"),
      },
      body: mockBody,
    });

    const url = "https://arxiv.org/pdf/2307.10265";
    const result = await downloadURIToFile(url);

    expect(result.success).toBe(true);
    expect(result.fileLocation).toBeTruthy();

    // The filename should end with .pdf, not .10265
    const filename = path.basename(result.fileLocation);
    expect(path.extname(filename)).toBe(".pdf");

    // Cleanup
    if (fs.existsSync(result.fileLocation)) fs.unlinkSync(result.fileLocation);
  });

  it("should append .txt extension for text/plain content type when URL has no extension", async () => {
    const mockBody = {
      pipe: jest.fn(),
      [Symbol.asyncIterator]: async function* () {
        yield Buffer.from("fake text content");
      },
    };

    global.fetch = jest.fn().mockResolvedValue({
      ok: true,
      status: 200,
      statusText: "OK",
      headers: {
        get: jest.fn().mockReturnValue("text/plain"),
      },
      body: mockBody,
    });

    const url = "https://example.com/data/export";
    const result = await downloadURIToFile(url);

    expect(result.success).toBe(true);
    const filename = path.basename(result.fileLocation);
    expect(path.extname(filename)).toBe(".txt");

    if (fs.existsSync(result.fileLocation)) fs.unlinkSync(result.fileLocation);
  });

  it("should not add extension when URL already has a known file extension", async () => {
    const mockBody = {
      pipe: jest.fn(),
      [Symbol.asyncIterator]: async function* () {
        yield Buffer.from("fake csv content");
      },
    };

    global.fetch = jest.fn().mockResolvedValue({
      ok: true,
      status: 200,
      statusText: "OK",
      headers: {
        get: jest.fn().mockReturnValue("text/csv"),
      },
      body: mockBody,
    });

    const url = "https://example.com/data.csv";
    const result = await downloadURIToFile(url);

    expect(result.success).toBe(true);
    const filename = path.basename(result.fileLocation);
    // Should keep .csv extension
    expect(path.extname(filename)).toBe(".csv");

    if (fs.existsSync(result.fileLocation)) fs.unlinkSync(result.fileLocation);
  });

  it("should handle content-type with charset parameter", async () => {
    const mockBody = {
      pipe: jest.fn(),
      [Symbol.asyncIterator]: async function* () {
        yield Buffer.from("fake html content");
      },
    };

    global.fetch = jest.fn().mockResolvedValue({
      ok: true,
      status: 200,
      statusText: "OK",
      headers: {
        get: jest.fn().mockReturnValue("text/html; charset=utf-8"),
      },
      body: mockBody,
    });

    const url = "https://example.com/page";
    const result = await downloadURIToFile(url);

    expect(result.success).toBe(true);
    const filename = path.basename(result.fileLocation);
    expect(path.extname(filename)).toBe(".html");

    if (fs.existsSync(result.fileLocation)) fs.unlinkSync(result.fileLocation);
  });

  it("should not add extension when Content-Type is not in ACCEPTED_MIMES", async () => {
    const mockBody = {
      pipe: jest.fn(),
      [Symbol.asyncIterator]: async function* () {
        yield Buffer.from("fake binary content");
      },
    };

    global.fetch = jest.fn().mockResolvedValue({
      ok: true,
      status: 200,
      statusText: "OK",
      headers: {
        get: jest.fn().mockReturnValue("application/octet-stream"),
      },
      body: mockBody,
    });

    const url = "https://example.com/download";
    const result = await downloadURIToFile(url);

    expect(result.success).toBe(true);
    const filename = path.basename(result.fileLocation);
    // Should not have a recognized extension appended
    expect(path.extname(filename)).toBe("");

    if (fs.existsSync(result.fileLocation)) fs.unlinkSync(result.fileLocation);
  });
});

