@@ -33,10 +33,25 @@ async function downloadURIToFile(url, maxTimeout = 10_000) {
       .finally(() => clearTimeout(timeout));

     const urlObj = new URL(url);
-    const filename = `${urlObj.hostname}-${slugify(
+    let filename = `${urlObj.hostname}-${slugify(
       urlObj.pathname.replace(/\//g, "-"),
       { lower: true }
     )}`;
+
+    // If the filename doesn't already have a supported extension, try to determine
+    // one from the Content-Type header so that processSingleFile can identify the file type.
+    const existingExt = path.extname(filename).toLowerCase();
+    if (!SUPPORTED_FILETYPE_CONVERTERS.hasOwnProperty(existingExt)) {
+      const contentType = res.headers.get("Content-Type")?.toLowerCase();
+      if (contentType) {
+        const mimeType = contentType.split(";")[0].trim();
+        if (ACCEPTED_MIMES.hasOwnProperty(mimeType)) {
+          const ext = ACCEPTED_MIMES[mimeType][0]; // Use the first mapped extension
+          filename = filename + ext;
+        }
+      }
+    }
+
     const localFilePath = path.join(WATCH_DIRECTORY, filename);
     const writeStream = fs.createWriteStream(localFilePath);
     await pipeline(res.body, writeStream);
